    "h(v);hi=hist.length}inp.value=''}else if(e.key=='ArrowUp'){if(hi>0){hi--;inp.value=hist[hi]||''}}else if(e.key"
    "=='ArrowDown'){if(hi<hist.length){hi++;inp.value=hist[hi]||''}}});conn()</script></body></html>";

